// Exemplo de lógica para o nó "Code"
const input = items[0].json;

let components = [];

// 1. Lógica de Header (Mídia)
if (input.media_type && input.media_url) {
  components.push({
    type: "HEADER",
    format: input.media_type.toUpperCase(), // IMAGE, VIDEO, DOCUMENT
    example: {
      header_handle: [input.media_url] // Ou link direto dependendo da versão da API
    }
  });
}

// 2. Lógica de Corpo (Texto e Variáveis)
let body = {
  type: "BODY",
  text: input.texto_principal
};

// Se houver variáveis, a Meta exige exemplos
if (input.variaveis_exemplo) {
  body.example = {
    body_text: [input.variaveis_exemplo.split(',')] // Ex: "João, 20%"
  };
}
components.push(body);

// 3. Lógica de Botões
if (input.botao_texto && input.botao_url) {
  components.push({
    type: "BUTTONS",
    buttons: [{
      type: "URL",
      text: input.botao_texto,
      url: input.botao_url
    }]
  });
}

return {
  name: input.nome_template.toLowerCase().replace(/ /g, "_"),
  category: "MARKETING",
  language: "pt_BR",
  components: components
};
